                let overlayObserver = null;
                let lockObserverBody = null;
                let lockObserverDocEl = null;
                let scheduled = false;
                let rafId = 0;
                let timeoutId = 0;
                let lastRunAt = 0;
                let lastEffectAt = Date.now();
