                        const href = rawHref && !/^https?:\/\//i.test(rawHref) ? String(fromSel.href || rawHref) : rawHref;
                        const abs0 = href ? toAbsHref(href, fromSel) : '';
                        const abs = abs0 ? (sanitizePanShareUrl(abs0) || abs0) : '';
