                const canSelectionOpenOnce = (ttlMsRaw) => {
                    const ttlMs = Math.max(300, Math.min(5000, Number(ttlMsRaw) || 900));
                    const now = Date.now();
                    const prev = lastSelectionOpenAt || 0;
                    if (prev && now - prev < ttlMs) return false;
                    lastSelectionOpenAt = now;
                    return true;
                };

